class SessionManager {
    static let shared = SessionManager()
    
    private var activeSession: UserSession?
    
    private init() {}
    
    func createSession(userId: String, token: String) -> UserSession {
        let session = UserSession(userId: userId, token: token, createdAt: Date())
        activeSession = session
        return session
    }
    
    func getActiveSession() -> UserSession? {
        guard let session = activeSession else { return nil }
        
        if session.isExpired() {
            activeSession = nil
            return nil
        }
        
        return session
    }
    
    func clearSession() {
        activeSession = nil
        BiometricAuthenticationManager.shared.clearSessionToken()
    }
    
    func isAuthenticated() -> Bool {
        return getActiveSession() != nil
    }
}

struct UserSession {
    let userId: String
    let token: String
    let createdAt: Date
    let expirationInterval: TimeInterval = 3600
    
    func isExpired() -> Bool {
        return Date().timeIntervalSince(createdAt) > expirationInterval
    }
}

